eElement('script');a.src = '/cdn-cgi/challenge-platform/h/g/orchestrate/chl_page/v1?ray=9e092a07ae5600f4';window._cf_chl_opt.cOgUHash = location.hash === '' && location.href.indexOf('#') !== -1 ? '#' : location.hash;window._cf_chl_opt.cOgUQuery = location.search === '' && location.href.slice(0, location.href.length - window._cf_chl_opt.cOgUHash.length).indexOf('?') !== -1 ? '?' : location.search;if (window.history && window.history.replaceState) {var ogU = location.pathname + window._cf_chl_opt.cOgUQuery + window._cf_chl_opt.cOgUHash;history.replaceState(null, null,\"/backend-api/codex/analytics-events/events?__cf_chl_rt_tk=9M6K1oWr8RorMFwIbGexLlU_VAm2TZ5LpLi0IK.uXKo-1774224113-1.0.1.1-5se3hu_LBtQX7ULHEYeplGnSB31EBNC.ZKIXqxgvqts\"+ window._cf_chl_opt.cOgUHash);a.onload = function() {history.replaceState(null, null, ogU);}}document.getElementsByTagName('head')[0].appendChild(a);}());</script></div>\n    </div>\n  </body>\n</html>\n\n","stdout":"{\"type\":\"thread.started\",\"thread_id\":\"019d17fe-a5ff-7ce2-abf0-fc336832c4bb\"}\n{\"type\":\"turn.started\"}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_0\",\"type\":\"agent_message\",\"text\":\"I’ll continue as CEO by checking current Paperclip task state first, then I’ll pick up the next actionable coordination step. I’m using the `paperclip` skill for control-plane task management and governance-compliant updates.\"}}\n{\"type\":\"item.started\",\"item\":{\"id\":\"item_1\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc \\\"sed -n '1,220p' /Users/rock.xu/github/paperclip-demo/runtime/node_modules/@paperclipai/adapter-codex-local/skills/paperclip/SKILL.md\\\"\",\"aggregated_output\":\"\",\"exit_code\":null,\"status\":\"in_progress\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_1\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc \\\"sed -n '1,220p' /Users/rock.xu/github/paperclip-demo/runtime/node_modules/@paperclipai/adapter-codex-local/skills/paperclip/SKILL.md\\\"\",\"aggregated_output\":\"---\\nname: paperclip\\ndescription: >\\n  Interact with the Paperclip control plane API to manage tasks, coordinate with\\n  other agents, and follow company governance. Use when you need to check\\n  assignments, update task status, delegate work, post comments, or call any\\n  Paperclip API endpoint. Do NOT use for the actual domain work itself (writing\\n  code, research, etc.) — only for Paperclip coordination.\\n---\\n\\n# Paperclip Skill\\n\\nYou run in **heartbeats** — short execution windows triggered by Paperclip. Each heartbeat, you wake up, check your work, do something useful, and exit. You do not run continuously.\\n\\n## Authentication\\n\\nEnv vars auto-injected: `PAPERCLIP_AGENT_ID`, `PAPERCLIP_COMPANY_ID`, `PAPERCLIP_API_URL`, `PAPERCLIP_RUN_ID`. Optional wake-context vars may also be present: `PAPERCLIP_TASK_ID` (issue/task that triggered this wake), `PAPERCLIP_WAKE_REASON` (why this run was triggered), `PAPERCLIP_WAKE_COMMENT_ID` (specific comment that triggered this wake), `PAPERCLIP_APPROVAL_ID`, `PAPERCLIP_APPROVAL_STATUS`, and `PAPERCLIP_LINKED_ISSUE_IDS` (comma-separated). For local adapters, `PAPERCLIP_API_KEY` is auto-injected as a short-lived run JWT. For non-local adapters, your operator should set `PAPERCLIP_API_KEY` in adapter config. All requests use `Authorization: Bearer $PAPERCLIP_API_KEY`. All endpoints under `/api`, all JSON. Never hard-code the API URL.\\n\\nManual local CLI mode (outside heartbeat runs): use `paperclipai agent local-cli <agent-id-or-shortname> --company-id <company-id>` to install Paperclip skills for Claude/Codex and print/export the required `PAPERCLIP_*` environment variables for that agent identity.\\n\\n**Run audit trail:** You MUST include `-H 'X-Paperclip-Run-Id: $PAPERCLIP_RUN_ID'` on ALL API requests that modify issues (checkout, update, comment, create subtask, release). This links your actions to the current heartbeat run for traceability.\\n\\n## The Heartbeat Procedure\\n\\nFollow these steps every time you wake up:\\n\\n**Step 1 — Identity.** If not already in context, `GET /api/agents/me` to get your id, companyId, role, chainOfCommand, and budget.\\n\\n**Step 2 — Approval follow-up (when triggered).** If `PAPERCLIP_APPROVAL_ID` is set (or wake reason indicates approval resolution), review the approval first:\\n\\n- `GET /api/approvals/{approvalId}`\\n- `GET /api/approvals/{approvalId}/issues`\\n- For each linked issue:\\n  - close it (`PATCH` status to `done`) if the approval fully resolves requested work, or\\n  - add a markdown comment explaining why it remains open and what happens next.\\n    Always include links to the approval and issue in that comment.\\n\\n**Step 3 — Get assignments.** Prefer `GET /api/agents/me/inbox-lite` for the normal heartbeat inbox. It returns the compact assignment list you need for prioritization. Fall back to `GET /api/companies/{companyId}/issues?assigneeAgentId={your-agent-id}&status=todo,in_progress,blocked` only when you need the full issue objects.\\n\\n**Step 4 — Pick work (with mention exception).** Work on `in_progress` first, then `todo`. Skip `blocked` unless you can unblock it.\\n**Blocked-task dedup:** Before working on a `blocked` task, fetch its comment thread. If your most recent comment was a blocked-status update AND no new comments from other agents or users have been posted since, skip the task entirely — do not checkout, do not post another comment. Exit the heartbeat (or move to the next task) instead. Only re-engage with a blocked task when new context exists (a new comment, status change, or event-based wake like `PAPERCLIP_WAKE_COMMENT_ID`).\\nIf `PAPERCLIP_TASK_ID` is set and that task is assigned to you, prioritize it first for this heartbeat.\\nIf this run was triggered by a comment mention (`PAPERCLIP_WAKE_COMMENT_ID` set; typically `PAPERCLIP_WAKE_REASON=issue_comment_mentioned`), you MUST read that comment thread first, even if the task is not currently assigned to you.\\nIf that mentioned comment explicitly asks you to take the task, you may self-assign by checking out `PAPERCLIP_TASK_ID` as yourself, then proceed normally.\\nIf the comment asks for input/review but not ownership, respond in comments if useful, then continue with assigned work.\\nIf the comment does not direct you to take ownership, do not self-assign.\\nIf nothing is assigned and there is no valid mention-based ownership handoff, exit the heartbeat.\\n\\n**Step 5 — Checkout.** You MUST checkout before doing any work. Include the run ID header:\\n\\n```\\nPOST /api/issues/{issueId}/checkout\\nHeaders: Authorization: Bearer $PAPERCLIP_API_KEY, X-Paperclip-Run-Id: $PAPERCLIP_RUN_ID\\n{ \\\"agentId\\\": \\\"{your-agent-id}\\\", \\\"expectedStatuses\\\": [\\\"todo\\\", \\\"backlog\\\", \\\"blocked\\\"] }\\n```\\n\\nIf already checked out by you, returns normally. If owned by another agent: `409 Conflict` — stop, pick a different task. **Never retry a 409.**\\n\\n**Step 6 — Understand context.** Prefer `GET /api/issues/{issueId}/heartbeat-context` first. It gives you compact issue state, ancestor summaries, goal/project info, and comment cursor metadata without forcing a full thread replay.\\n\\nUse comments incrementally:\\n\\n- if `PAPERCLIP_WAKE_COMMENT_ID` is set, fetch that exact comment first with `GET /api/issues/{issueId}/comments/{commentId}`\\n- if you already know the thread and only need updates, use `GET /api/issues/{issueId}/comments?after={last-seen-comment-id}&order=asc`\\n- use the full `GET /api/issues/{issueId}/comments` route only when you are cold-starting, when session memory is unreliable, or when the incremental path is not enough\\n\\nRead enough ancestor/comment context to understand _why_ the task exists and what changed. Do not reflexively reload the whole thread on every heartbeat.\\n\\n**Step 7 — Do the work.** Use your tools and capabilities.\\n\\n**Step 8 — Update status and communicate.** Always include the run ID header.\\nIf you are blocked at any point, you MUST update the issue to `blocked` before exiting the heartbeat, with a comment that explains the blocker and who needs to act.\\n\\n```json\\nPATCH /api/issues/{issueId}\\nHeaders: X-Paperclip-Run-Id: $PAPERCLIP_RUN_ID\\n{ \\\"status\\\": \\\"done\\\", \\\"comment\\\": \\\"What was done and why.\\\" }\\n\\nPATCH /api/issues/{issueId}\\nHeaders: X-Paperclip-Run-Id: $PAPERCLIP_RUN_ID\\n{ \\\"status\\\": \\\"blocked\\\", \\\"comment\\\": \\\"What is blocked, why, and who needs to unblock it.\\\" }\\n```\\n\\nStatus values: `backlog`, `todo`, `in_progress`, `in_review`, `done`, `blocked`, `cancelled`. Priority values: `critical`, `high`, `medium`, `low`. Other updatable fields: `title`, `description`, `priority`, `assigneeAgentId`, `projectId`, `goalId`, `parentId`, `billingCode`.\\n\\n**Step 9 — Delegate if needed.** Create subtasks with `POST /api/companies/{companyId}/issues`. Always set `parentId` and `goalId`. Set `billingCode` for cross-team work.\\n\\n## Project Setup Workflow (CEO/Manager Common Path)\\n\\nWhen asked to set up a new project with workspace config (local folder and/or GitHub repo), use:\\n\\n1. `POST /api/companies/{companyId}/projects` with project fields.\\n2. Optionally include `workspace` in that same create call, or call `POST /api/projects/{projectId}/workspaces` right after create.\\n\\nWorkspace rules:\\n\\n- Provide at least one of `cwd` (local folder) or `repoUrl` (remote repo).\\n- For repo-only setup, omit `cwd` and provide `repoUrl`.\\n- Include both `cwd` + `repoUrl` when local and remote references should both be tracked.\\n\\n## OpenClaw Invite Workflow (CEO)\\n\\nUse this when asked to invite a new OpenClaw employee.\\n\\n1. Generate a fresh OpenClaw invite prompt:\\n\\n```\\nPOST /api/companies/{companyId}/openclaw/invite-prompt\\n{ \\\"agentMessage\\\": \\\"optional onboarding note for OpenClaw\\\" }\\n```\\n\\nAccess control:\\n\\n- Board users with invite permission can call it.\\n- Agent callers: only the company CEO agent can call it.\\n\\n2. Build the copy-ready OpenClaw prompt for the board:\\n\\n- Use `onboardingTextUrl` from the response.\\n- Ask the board to paste that prompt into OpenClaw.\\n- If the issue includes an OpenClaw URL (for example `ws://127.0.0.1:18789`), include that URL in your comment so the board/OpenClaw uses it in `agentDefaultsPayload.url`.\\n\\n3. Post the prompt in the issue comment so the human can paste it into OpenClaw.\\n\\n4. After OpenClaw submits the join request, monitor approvals and continue onboarding (approval + API key claim + skill install).\\n\\n## Critical Rules\\n\\n- **Always checkout** before working. Never PATCH to `in_progress` manually.\\n- **Never retry a 409.** The task belongs to someone else.\\n- **Never look for unassigned work.**\\n- **Self-assign only for explicit @-mention handoff.** This requires a mention-triggered wake with `PAPERCLIP_WAKE_COMMENT_ID` and a comment that clearly directs you to do the task. Use checkout (never direct assignee patch). Otherwise, no assignments = exit.\\n- **Honor \\\"send it back to me\\\" requests from board users.** If a board/user asks for review handoff (e.g. \\\"let me review it\\\", \\\"assign it back to me\\\"), reassign the issue to that user with `assigneeAgentId: null` and `assigneeUserId: \\\"<requesting-user-id>\\\"`, and typically set status to `in_review` instead of `done`.\\n  Resolve requesting user id from the triggering comment thread (`authorUserId`) when available; otherwise use the issue's `createdByUserId` if it matches the requester context.\\n- **Always comment** on `in_progress` work before exiting a heartbeat — **except** for blocked tasks with no new context (see blocked-task dedup in Step 4).\\n- **Always set `parentId`** on subtasks (and `goalId` unless you're CEO/manager creating top-level work).\\n- **Never cancel cross-team tasks.** Reassign to your manager with a comment.\\n- **Always update blocked issues explicitly.** If blocked, PATCH status to `blocked` with a blocker comment before exiting, then escalate. On subsequent heartbeats, do NOT repeat the same blocked comment — see blocked-task dedup in Step 4.\\n- **@-mentions** (`@AgentName` in comments) trigger heartbeats — use sparingly, they cost budget.\\n- **Budget**: auto-paused at 100%. Above 80%, focus on critical tasks only.\\n- **Escalate** via `chainOfCommand` when stuck. Reassign to manager or create a task for them.\\n- **Hiring**: use `paperclip-create-agent` skill for new agent creation workflows.\\n- **Commit Co-author**: if you make a git commit you MUST add `Co-Authored-By: Paperclip <noreply@paperclip.ing>` to the end of each commit message\\n\\n## Comment Style (Required)\\n\\nWhen posting issue comments, use concise markdown with:\\n\\n- a short status line\\n- bullets for what changed / what is blocked\\n- links to related entities when available\\n\\n**Company-prefixed URLs (required):** All internal links MUST include the company prefix. Derive the prefix from any issue identifier you have (e.g., `PAP-315` → prefix is `PAP`). Use this prefix in all UI links:\\n\\n- Issues: `/<prefix>/issues/<issue-identifier>` (e.g., `/PAP/issues/PAP-224`)\\n- Issue comments: `/<prefix>/issues/<issue-identifier>#comment-<comment-id>` (deep link to a specific comment)\\n- Issue documents: `/<prefix>/issues/<issue-identifier>#document-<document-key>` (deep link to a specific document such as `plan`)\\n- Agents: `/<prefix>/agents/<agent-url-key>` (e.g., `/PAP/agents/claudecoder`)\\n- Projects: `/<prefix>/projects/<project-url-key>` (id fallback allowed)\\n- Approvals: `/<prefix>/approvals/<approval-id>`\\n- Runs: `/<prefix>/agents/<agent-url-key-or-id>/runs/<run-id>`\\n\\nDo NOT use unprefixed paths like `/issues/PAP-123` or `/agents/cto` — always include the company prefix.\\n\\nExample:\\n\\n```md\\n## Update\\n\\nSubmitted CTO hire request and linked it for board review.\\n\\n- Approval: [ca6ba09d](/PAP/approvals/ca6ba09d-b558-4a53-a552-e7ef87e54a1b)\\n- Pending agent: [CTO draft](/PAP/agents/cto)\\n- Source issue: [PC-142](/PAP/issues/PC-142)\\n```\\n\\n## Planning (Required when planning requested)\\n\\nIf you're asked to make a plan, create or update the issue document with key `plan`. Do not append plans into the issue description anymore. If you're asked for plan revisions, update that same `plan` document. In both cases, leave a comment as you normally would and mention that you updated the plan document.\\n\\nWhen you mention a plan or another issue document in a comment, include a direct document link using the key:\\n\\n- Plan: `/<prefix>/issues/<issue-identifier>#document-plan`\\n- Generic document: `/<prefix>/issues/<issue-identifier>#document-<document-key>`\\n\\nIf the issue identifier is available, prefer the document deep link over a plain issue link so the reader lands directly on the updated document.\\n\\nIf you're asked to make a plan, _do not mark the issue as done_. Re-assign the issue to whomever asked you to make the plan and leave it in progress.\\n\\nRecommended API flow:\\n\\n```bash\\nPUT /api/issues/{issueId}/documents/plan\\n{\\n  \\\"title\\\": \\\"Plan\\\",\\n  \\\"format\\\": \\\"markdown\\\",\\n  \\\"body\\\": \\\"# Plan\\\\n\\\\n[your plan here]\\\",\\n  \\\"baseRevisionId\\\": null\\n}\\n```\\n\\nIf `plan` already exists, fetch the current document first and send its latest `baseRevisionId` when you update it.\\n\\n## Setting Agent Instructions Path\\n\\nUse the dedicated route instead of generic `PATCH /api/agents/:id` when you need to set an agent's instructions markdown path (for example `AGENTS.md`).\\n\\n```bash\\nPATCH /api/agents/{agentId}/instructions-path\\n{\\n  \\\"path\\\": \\\"agents/cmo/AGENTS.md\\\"\\n}\\n```\\n\\nRules:\\n\\n- Allowed for: the target agent itself, or an ancestor manager in that agent's reporting chain.\\n- For `codex_local` and `claude_local`, default config key is `instructionsFilePath`.\\n- Relative paths are resolved against the target agent's `adapterConfig.cwd`; absolute paths are accepted as-is.\\n- To clear the path, send `{ \\\"path\\\": null }`.\\n\",\"exit_code\":0,\"status\":\"completed\"}}\n{\"type\":\"item.started\",\"item\":{\"id\":\"item_2\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'pwd && ls -la'\",\"aggregated_output\":\"\",\"exit_code\":null,\"status\":\"in_progress\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_2\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'pwd && ls -la'\",\"aggregated_output\":\"/Users/rock.xu/github/paperclip-demo/.paperclip-home/instances/demo/workspaces/d740f254-e1b7-4429-a639-dd1a34af65d1\\ntotal 0\\ndrwxr-xr-x@ 2 rock.xu  staff  64 Mar 23 08:00 .\\ndrwxr-xr-x@ 3 rock.xu  staff  96 Mar 23 08:00 ..\\n\",\"exit_code\":0,\"status\":\"completed\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_3\",\"type\":\"agent_message\",\"text\":\"I’ve loaded the Paperclip workflow instructions. Next I’ll run the heartbeat sequence from your current agent context: identity, inbox, then continue the top-priority assigned issue with checkout and status updates.\"}}\n{\"type\":\"item.started\",\"item\":{\"id\":\"item_4\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc \\\"env | rg '\\\"'^PAPERCLIP_'\\\"' | sort\\\"\",\"aggregated_output\":\"\",\"exit_code\":null,\"status\":\"in_progress\"}}\n{\"type\":\"item.started\",\"item\":{\"id\":\"item_5\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'printenv PAPERCLIP_API_URL PAPERCLIP_API_KEY PAPERCLIP_AGENT_ID PAPERCLIP_COMPANY_ID PAPERCLIP_RUN_ID PAPERCLIP_TASK_ID PAPERCLIP_WAKE_REASON PAPERCLIP_WAKE_COMMENT_ID PAPERCLIP_APPROVAL_ID PAPERCLIP_APPROVAL_STATUS PAPERCLIP_LINKED_ISSUE_IDS'\",\"aggregated_output\":\"\",\"exit_code\":null,\"status\":\"in_progress\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_5\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'printenv PAPERCLIP_API_URL PAPERCLIP_API_KEY PAPERCLIP_AGENT_ID PAPERCLIP_COMPANY_ID PAPERCLIP_RUN_ID PAPERCLIP_TASK_ID PAPERCLIP_WAKE_REASON PAPERCLIP_WAKE_COMMENT_ID PAPERCLIP_APPROVAL_ID PAPERCLIP_APPROVAL_STATUS PAPERCLIP_LINKED_ISSUE_IDS'\",\"aggregated_output\":\"http://127.0.0.1:3100\\n\",\"exit_code\":0,\"status\":\"completed\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_4\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc \\\"env | rg '\\\"'^PAPERCLIP_'\\\"' | sort\\\"\",\"aggregated_output\":\"PAPERCLIP_AGENT_ID=d740f254-e1b7-4429-a639-dd1a34af65d1\\nPAPERCLIP_AGENT_JWT_SECRET=1c6ad87bba0767c5fdb40d0909c00d3e5eb71fdf534235655b25189dac175edc\\nPAPERCLIP_API_KEY=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9..xCYT1KGxVmepvAROepSIou0Nht2bT2VWzlt0eJX-sic\\nPAPERCLIP_API_URL=http://127.0.0.1:3100\\nPAPERCLIP_COMPANY_ID=8e6a9f7a-8cc9-4d7f-80f1-ddd498291f7e\\nPAPERCLIP_CONFIG=/Users/rock.xu/github/paperclip-demo/.paperclip-home/config.json\\nPAPERCLIP_HOME=/Users/rock.xu/github/paperclip-demo/.paperclip-home\\nPAPERCLIP_INSTANCE_ID=demo\\nPAPERCLIP_LISTEN_HOST=127.0.0.1\\nPAPERCLIP_LISTEN_PORT=3100\\nPAPERCLIP_OPEN_ON_LISTEN=false\\nPAPERCLIP_RUN_ID=ea60d99b-02a6-4e2d-b13d-6a59c1cf0a92\\nPAPERCLIP_SECRETS_MASTER_KEY_FILE=/Users/rock.xu/github/paperclip-demo/.paperclip-home/instances/demo/secrets/master.key\\nPAPERCLIP_SECRETS_PROVIDER=local_encrypted\\nPAPERCLIP_SECRETS_STRICT_MODE=false\\nPAPERCLIP_TASK_ID=d53e44b3-4d58-46bf-a3ff-4ddb4a54557f\\nPAPERCLIP_WAKE_REASON=issue_assigned\\nPAPERCLIP_WORKSPACE_CWD=/Users/rock.xu/github/paperclip-demo/.paperclip-home/instances/demo/workspaces/d740f254-e1b7-4429-a639-dd1a34af65d1\\nPAPERCLIP_WORKSPACE_SOURCE=agent_home\\nPAPERCLIP_WORKSPACE_STRATEGY=project_primary\\n\",\"exit_code\":0,\"status\":\"completed\"}}\n{\"type\":\"item.started\",\"item\":{\"id\":\"item_6\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'curl -sS -H \\\"Authorization: Bearer $PAPERCLIP_API_KEY\\\" \\\"$PAPERCLIP_API_URL/api/agents/me/inbox-lite\\\"'\",\"aggregated_output\":\"\",\"exit_code\":null,\"status\":\"in_progress\"}}\n{\"type\":\"item.started\",\"item\":{\"id\":\"item_7\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'curl -sS -H \\\"Authorization: Bearer $PAPERCLIP_API_KEY\\\" \\\"$PAPERCLIP_API_URL/api/agents/me\\\"'\",\"aggregated_output\":\"\",\"exit_code\":null,\"status\":\"in_progress\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_7\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'curl -sS -H \\\"Authorization: Bearer $PAPERCLIP_API_KEY\\\" \\\"$PAPERCLIP_API_URL/api/agents/me\\\"'\",\"aggregated_output\":\"{\\\"id\\\":\\\"d740f254-e1b7-4429-a639-dd1a34af65d1\\\",\\\"companyId\\\":\\\"8e6a9f7a-8cc9-4d7f-80f1-ddd498291f7e\\\",\\\"name\\\":\\\"CEO\\\",\\\"role\\\":\\\"ceo\\\",\\\"title\\\":null,\\\"icon\\\":null,\\\"status\\\":\\\"running\\\",\\\"reportsTo\\\":null,\\\"capabilities\\\":null,\\\"adapterType\\\":\\\"codex_local\\\",\\\"adapterConfig\\\":{\\\"model\\\":\\\"gpt-5.3-codex\\\",\\\"search\\\":false,\\\"graceSec\\\":15,\\\"timeoutSec\\\":0,\\\"dangerouslyBypassApprovalsAndSandbox\\\":true},\\\"runtimeConfig\\\":{\\\"heartbeat\\\":{\\\"enabled\\\":true,\\\"cooldownSec\\\":10,\\\"intervalSec\\\":3600,\\\"wakeOnDemand\\\":true,\\\"maxConcurrentRuns\\\":1}},\\\"budgetMonthlyCents\\\":0,\\\"spentMonthlyCents\\\":0,\\\"pauseReason\\\":null,\\\"pausedAt\\\":null,\\\"permissions\\\":{\\\"canCreateAgents\\\":true},\\\"lastHeartbeatAt\\\":null,\\\"metadata\\\":null,\\\"createdAt\\\":\\\"2026-03-23T00:00:47.530Z\\\",\\\"updatedAt\\\":\\\"2026-03-23T00:00:57.662Z\\\",\\\"urlKey\\\":\\\"ceo\\\",\\\"chainOfCommand\\\":[]}\",\"exit_code\":0,\"status\":\"completed\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_6\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'curl -sS -H \\\"Authorization: Bearer $PAPERCLIP_API_KEY\\\" \\\"$PAPERCLIP_API_URL/api/agents/me/inbox-lite\\\"'\",\"aggregated_output\":\"[{\\\"id\\\":\\\"d53e44b3-4d58-46bf-a3ff-4ddb4a54557f\\\",\\\"identifier\\\":\\\"ABC-1\\\",\\\"title\\\":\\\"Create your CEO HEARTBEAT.md\\\",\\\"status\\\":\\\"todo\\\",\\\"priority\\\":\\\"medium\\\",\\\"projectId\\\":null,\\\"goalId\\\":null,\\\"parentId\\\":null,\\\"updatedAt\\\":\\\"2026-03-23T00:00:57.600Z\\\",\\\"activeRun\\\":{\\\"id\\\":\\\"ea60d99b-02a6-4e2d-b13d-6a59c1cf0a92\\\",\\\"status\\\":\\\"running\\\",\\\"agentId\\\":\\\"d740f254-e1b7-4429-a639-dd1a34af65d1\\\",\\\"invocationSource\\\":\\\"assignment\\\",\\\"triggerDetail\\\":\\\"system\\\",\\\"startedAt\\\":\\\"2026-03-23T00:00:57.618Z\\\",\\\"finishedAt\\\":null,\\\"createdAt\\\":\\\"2026-03-23T00:00:57.572Z\\\"}}]\",\"exit_code\":0,\"status\":\"completed\"}}\n{\"type\":\"item.started\",\"item\":{\"id\":\"item_8\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'curl -sS -H \\\"Authorization: Bearer $PAPERCLIP_API_KEY\\\" \\\"$PAPERCLIP_API_URL/api/issues/$PAPERCLIP_TASK_ID/heartbeat-context\\\"'\",\"aggregated_output\":\"\",\"exit_code\":null,\"status\":\"in_progress\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_8\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'curl -sS -H \\\"Authorization: Bearer $PAPERCLIP_API_KEY\\\" \\\"$PAPERCLIP_API_URL/api/issues/$PAPERCLIP_TASK_ID/heartbeat-context\\\"'\",\"aggregated_output\":\"{\\\"issue\\\":{\\\"id\\\":\\\"d53e44b3-4d58-46bf-a3ff-4ddb4a54557f\\\",\\\"identifier\\\":\\\"ABC-1\\\",\\\"title\\\":\\\"Create your CEO HEARTBEAT.md\\\",\\\"description\\\":\\\"Setup yourself as the CEO. Use the ceo persona found here: \\\\n\\\\nhttps://github.com/paperclipai/companies/blob/main/default/ceo/AGENTS.md\\\\n\\\\nEnsure you have a folder agents/ceo and then download this AGENTS.md, and sibling HEARTBEAT.md, SOUL.md, and TOOLS.md. and set that AGENTS.md as the path to your agents instruction file\\\\n\\\\nAfter that, hire yourself a Founding Engineer agent and then plan the roadmap and tasks for your new company.\\\",\\\"status\\\":\\\"todo\\\",\\\"priority\\\":\\\"medium\\\",\\\"projectId\\\":null,\\\"goalId\\\":null,\\\"parentId\\\":null,\\\"assigneeAgentId\\\":\\\"d740f254-e1b7-4429-a639-dd1a34af65d1\\\",\\\"assigneeUserId\\\":null,\\\"updatedAt\\\":\\\"2026-03-23T00:00:57.600Z\\\"},\\\"ancestors\\\":[],\\\"project\\\":null,\\\"goal\\\":null,\\\"commentCursor\\\":{\\\"totalComments\\\":0,\\\"latestCommentId\\\":null,\\\"latestCommentAt\\\":null},\\\"wakeComment\\\":null}\",\"exit_code\":0,\"status\":\"completed\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_9\",\"type\":\"agent_message\",\"text\":\"I found your active assignment `ABC-1` with concrete setup steps. Next I’ll checkout the issue, create `agents/ceo` with the required docs, set your instructions path, then use the hiring workflow to create the Founding Engineer agent and post a progress update.\"}}\n{\"type\":\"item.started\",\"item\":{\"id\":\"item_10\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc \\\"sed -n '1,260p' /Users/rock.xu/github/paperclip-demo/runtime/node_modules/@paperclipai/adapter-codex-local/skills/paperclip-create-agent/SKILL.md\\\"\",\"aggregated_output\":\"\",\"exit_code\":null,\"status\":\"in_progress\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_10\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc \\\"sed -n '1,260p' /Users/rock.xu/github/paperclip-demo/runtime/node_modules/@paperclipai/adapter-codex-local/skills/paperclip-create-agent/SKILL.md\\\"\",\"aggregated_output\":\"---\\nname: paperclip-create-agent\\ndescription: >\\n  Create new agents in Paperclip with governance-aware hiring. Use when you need\\n  to inspect adapter configuration options, compare existing agent configs,\\n  draft a new agent prompt/config, and submit a hire request.\\n---\\n\\n# Paperclip Create Agent Skill\\n\\nUse this skill when you are asked to hire/create an agent.\\n\\n## Preconditions\\n\\nYou need either:\\n\\n- board access, or\\n- agent permission `can_create_agents=true` in your company\\n\\nIf you do not have this permission, escalate to your CEO or board.\\n\\n## Workflow\\n\\n1. Confirm identity and company context.\\n\\n```sh\\ncurl -sS \\\"$PAPERCLIP_API_URL/api/agents/me\\\" \\\\\\n  -H \\\"Authorization: Bearer $PAPERCLIP_API_KEY\\\"\\n```\\n\\n2. Discover available adapter configuration docs for this Paperclip instance.\\n\\n```sh\\ncurl -sS \\\"$PAPERCLIP_API_URL/llms/agent-configuration.txt\\\" \\\\\\n  -H \\\"Authorization: Bearer $PAPERCLIP_API_KEY\\\"\\n```\\n\\n3. Read adapter-specific docs (example: `claude_local`).\\n\\n```sh\\ncurl -sS \\\"$PAPERCLIP_API_URL/llms/agent-configuration/claude_local.txt\\\" \\\\\\n  -H \\\"Authorization: Bearer $PAPERCLIP_API_KEY\\\"\\n```\\n\\n4. Compare existing agent configurations in your company.\\n\\n```sh\\ncurl -sS \\\"$PAPERCLIP_API_URL/api/companies/$PAPERCLIP_COMPANY_ID/agent-configurations\\\" \\\\\\n  -H \\\"Authorization: Bearer $PAPERCLIP_API_KEY\\\"\\n```\\n\\n5. Discover allowed agent icons and pick one that matches the role.\\n\\n```sh\\ncurl -sS \\\"$PAPERCLIP_API_URL/llms/agent-icons.txt\\\" \\\\\\n  -H \\\"Authorization: Bearer $PAPERCLIP_API_KEY\\\"\\n```\\n\\n6. Draft the new hire config:\\n- role/title/name\\n- icon (required in practice; use one from `/llms/agent-icons.txt`)\\n- reporting line (`reportsTo`)\\n- adapter type\\n- adapter and runtime config aligned to this environment\\n- capabilities\\n- run prompt in adapter config (`promptTemplate` where applicable)\\n- source issue linkage (`sourceIssueId` or `sourceIssueIds`) when this hire came from an issue\\n\\n7. Submit hire request.\\n\\n```sh\\ncurl -sS -X POST \\\"$PAPERCLIP_API_URL/api/companies/$PAPERCLIP_COMPANY_ID/agent-hires\\\" \\\\\\n  -H \\\"Authorization: Bearer $PAPERCLIP_API_KEY\\\" \\\\\\n  -H \\\"Content-Type: application/json\\\" \\\\\\n  -d '{\\n    \\\"name\\\": \\\"CTO\\\",\\n    \\\"role\\\": \\\"cto\\\",\\n    \\\"title\\\": \\\"Chief Technology Officer\\\",\\n    \\\"icon\\\": \\\"crown\\\",\\n    \\\"reportsTo\\\": \\\"<ceo-agent-id>\\\",\\n    \\\"capabilities\\\": \\\"Owns technical roadmap, architecture, staffing, execution\\\",\\n    \\\"adapterType\\\": \\\"codex_local\\\",\\n    \\\"adapterConfig\\\": {\\\"cwd\\\": \\\"/abs/path/to/repo\\\", \\\"model\\\": \\\"o4-mini\\\"},\\n    \\\"runtimeConfig\\\": {\\\"heartbeat\\\": {\\\"enabled\\\": true, \\\"intervalSec\\\": 300, \\\"wakeOnDemand\\\": true}},\\n    \\\"sourceIssueId\\\": \\\"<issue-id>\\\"\\n  }'\\n```\\n\\n8. Handle governance state:\\n- if response has `approval`, hire is `pending_approval`\\n- monitor and discuss on approval thread\\n- when the board approves, you will be woken with `PAPERCLIP_APPROVAL_ID`; read linked issues and close/comment follow-up\\n\\n```sh\\ncurl -sS \\\"$PAPERCLIP_API_URL/api/approvals/<approval-id>\\\" \\\\\\n  -H \\\"Authorization: Bearer $PAPERCLIP_API_KEY\\\"\\n\\ncurl -sS -X POST \\\"$PAPERCLIP_API_URL/api/approvals/<approval-id>/comments\\\" \\\\\\n  -H \\\"Authorization: Bearer $PAPERCLIP_API_KEY\\\" \\\\\\n  -H \\\"Content-Type: application/json\\\" \\\\\\n  -d '{\\\"body\\\":\\\"## CTO hire request submitted\\\\n\\\\n- Approval: [<approval-id>](/approvals/<approval-id>)\\\\n- Pending agent: [<agent-ref>](/agents/<agent-url-key-or-id>)\\\\n- Source issue: [<issue-ref>](/issues/<issue-identifier-or-id>)\\\\n\\\\nUpdated prompt and adapter config per board feedback.\\\"}'\\n```\\n\\nIf the approval already exists and needs manual linking to the issue:\\n\\n```sh\\ncurl -sS -X POST \\\"$PAPERCLIP_API_URL/api/issues/<issue-id>/approvals\\\" \\\\\\n  -H \\\"Authorization: Bearer $PAPERCLIP_API_KEY\\\" \\\\\\n  -H \\\"Content-Type: application/json\\\" \\\\\\n  -d '{\\\"approvalId\\\":\\\"<approval-id>\\\"}'\\n```\\n\\nAfter approval is granted, run this follow-up loop:\\n\\n```sh\\ncurl -sS \\\"$PAPERCLIP_API_URL/api/approvals/$PAPERCLIP_APPROVAL_ID\\\" \\\\\\n  -H \\\"Authorization: Bearer $PAPERCLIP_API_KEY\\\"\\n\\ncurl -sS \\\"$PAPERCLIP_API_URL/api/approvals/$PAPERCLIP_APPROVAL_ID/issues\\\" \\\\\\n  -H \\\"Authorization: Bearer $PAPERCLIP_API_KEY\\\"\\n```\\n\\nFor each linked issue, either:\\n- close it if approval resolved the request, or\\n- comment in markdown with links to the approval and next actions.\\n\\n## Quality Bar\\n\\nBefore sending a hire request:\\n\\n- Reuse proven config patterns from related agents where possible.\\n- Set a concrete `icon` from `/llms/agent-icons.txt` so the new hire is identifiable in org and task views.\\n- Avoid secrets in plain text unless required by adapter behavior.\\n- Ensure reporting line is correct and in-company.\\n- Ensure prompt is role-specific and operationally scoped.\\n- If board requests revision, update payload and resubmit through approval flow.\\n\\nFor endpoint payload shapes and full examples, read:\\n`skills/paperclip-create-agent/references/api-reference.md`\\n\",\"exit_code\":0,\"status\":\"completed\"}}\n{\"type\":\"item.started\",\"item\":{\"id\":\"item_11\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'curl -sS -X POST -H \\\"Authorization: Bearer $PAPERCLIP_API_KEY\\\" -H \\\"Content-Type: application/json\\\" -H \\\"X-Paperclip-Run-Id: $PAPERCLIP_RUN_ID\\\" \\\"$PAPERCLIP_API_URL/api/issues/$PAPERCLIP_TASK_ID/checkout\\\" -d '\\\"'{\\\\\\\"agentId\\\\\\\":\\\\\\\"'\\\\\\\"\\\"'$PAPERCLIP_AGENT_ID\\\"'\\\"'\\\\\\\",\\\\\\\"expectedStatuses\\\\\\\":[\\\\\\\"todo\\\\\\\",\\\\\\\"backlog\\\\\\\",\\\\\\\"blocked\\\\\\\"]}'\\\"\",\"aggregated_output\":\"\",\"exit_code\":null,\"status\":\"in_progress\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_11\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'curl -sS -X POST -H \\\"Authorization: Bearer $PAPERCLIP_API_KEY\\\" -H \\\"Content-Type: application/json\\\" -H \\\"X-Paperclip-Run-Id: $PAPERCLIP_RUN_ID\\\" \\\"$PAPERCLIP_API_URL/api/issues/$PAPERCLIP_TASK_ID/checkout\\\" -d '\\\"'{\\\\\\\"agentId\\\\\\\":\\\\\\\"'\\\\\\\"\\\"'$PAPERCLIP_AGENT_ID\\\"'\\\"'\\\\\\\",\\\\\\\"expectedStatuses\\\\\\\":[\\\\\\\"todo\\\\\\\",\\\\\\\"backlog\\\\\\\",\\\\\\\"blocked\\\\\\\"]}'\\\"\",\"aggregated_output\":\"{\\\"id\\\":\\\"d53e44b3-4d58-46bf-a3ff-4ddb4a54557f\\\",\\\"companyId\\\":\\\"8e6a9f7a-8cc9-4d7f-80f1-ddd498291f7e\\\",\\\"projectId\\\":null,\\\"projectWorkspaceId\\\":null,\\\"goalId\\\":null,\\\"parentId\\\":null,\\\"title\\\":\\\"Create your CEO HEARTBEAT.md\\\",\\\"description\\\":\\\"Setup yourself as the CEO. Use the ceo persona found here: \\\\n\\\\nhttps://github.com/paperclipai/companies/blob/main/default/ceo/AGENTS.md\\\\n\\\\nEnsure you have a folder agents/ceo and then download this AGENTS.md, and sibling HEARTBEAT.md, SOUL.md, and TOOLS.md. and set that AGENTS.md as the path to your agents instruction file\\\\n\\\\nAfter that, hire yourself a Founding Engineer agent and then plan the roadmap and tasks for your new company.\\\",\\\"status\\\":\\\"in_progress\\\",\\\"priority\\\":\\\"medium\\\",\\\"assigneeAgentId\\\":\\\"d740f254-e1b7-4429-a639-dd1a34af65d1\\\",\\\"assigneeUserId\\\":null,\\\"checkoutRunId\\\":\\\"ea60d99b-02a6-4e2d-b13d-6a59c1cf0a92\\\",\\\"executionRunId\\\":\\\"ea60d99b-02a6-4e2d-b13d-6a59c1cf0a92\\\",\\\"executionAgentNameKey\\\":\\\"ceo\\\",\\\"executionLockedAt\\\":\\\"2026-03-23T00:00:57.600Z\\\",\\\"createdByAgentId\\\":null,\\\"createdByUserId\\\":\\\"local-board\\\",\\\"issueNumber\\\":1,\\\"identifier\\\":\\\"ABC-1\\\",\\\"requestDepth\\\":0,\\\"billingCode\\\":null,\\\"assigneeAdapterOverrides\\\":null,\\\"executionWorkspaceId\\\":null,\\\"executionWorkspacePreference\\\":null,\\\"executionWorkspaceSettings\\\":null,\\\"startedAt\\\":\\\"2026-03-23T00:01:53.451Z\\\",\\\"completedAt\\\":null,\\\"cancelledAt\\\":null,\\\"hiddenAt\\\":null,\\\"createdAt\\\":\\\"2026-03-23T00:00:57.362Z\\\",\\\"updatedAt\\\":\\\"2026-03-23T00:01:53.451Z\\\",\\\"labels\\\":[],\\\"labelIds\\\":[]}\",\"exit_code\":0,\"status\":\"completed\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_12\",\"type\":\"agent_message\",\"text\":\"Checkout is complete and the issue is now `in_progress`. I’m now creating `agents/ceo` and pulling the four CEO persona files from the referenced repository, then I’ll set `AGENTS.md` as your instructions path.\"}}\n{\"type\":\"item.started\",\"item\":{\"id\":\"item_13\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'mkdir -p agents/ceo && for f in AGENTS.md HEARTBEAT.md SOUL.md TOOLS.md; do curl -fsSL \\\"https://raw.githubusercontent.com/paperclipai/companies/main/default/ceo/$f\\\" -o \\\"agents/ceo/$f\\\"; done && ls -la agents/ceo'\",\"aggregated_output\":\"\",\"exit_code\":null,\"status\":\"in_progress\"}}\n{\"type\":\"item.started\",\"item\":{\"id\":\"item_14\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'curl -sS -X PATCH -H \\\"Authorization: Bearer $PAPERCLIP_API_KEY\\\" -H \\\"Content-Type: application/json\\\" \\\"$PAPERCLIP_API_URL/api/agents/$PAPERCLIP_AGENT_ID/instructions-path\\\" -d '\\\"'{\\\\\\\"path\\\\\\\":\\\\\\\"agents/ceo/AGENTS.md\\\\\\\"}'\\\"\",\"aggregated_output\":\"\",\"exit_code\":null,\"status\":\"in_progress\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_14\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'curl -sS -X PATCH -H \\\"Authorization: Bearer $PAPERCLIP_API_KEY\\\" -H \\\"Content-Type: application/json\\\" \\\"$PAPERCLIP_API_URL/api/agents/$PAPERCLIP_AGENT_ID/instructions-path\\\" -d '\\\"'{\\\\\\\"path\\\\\\\":\\\\\\\"agents/ceo/AGENTS.md\\\\\\\"}'\\\"\",\"aggregated_output\":\"{\\\"error\\\":\\\"Relative instructions path requires adapterConfig.cwd to be set to an absolute path\\\"}\",\"exit_code\":0,\"status\":\"completed\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_13\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'mkdir -p agents/ceo && for f in AGENTS.md HEARTBEAT.md SOUL.md TOOLS.md; do curl -fsSL \\\"https://raw.githubusercontent.com/paperclipai/companies/main/default/ceo/$f\\\" -o \\\"agents/ceo/$f\\\"; done && ls -la agents/ceo'\",\"aggregated_output\":\"total 32\\ndrwxr-xr-x@ 6 rock.xu  staff   192 Mar 23 08:02 .\\ndrwxr-x