eElement('script');a.src = '/cdn-cgi/challenge-platform/h/g/orchestrate/chl_page/v1?ray=9e092e2e3a298391';window._cf_chl_opt.cOgUHash = location.hash === '' && location.href.indexOf('#') !== -1 ? '#' : location.hash;window._cf_chl_opt.cOgUQuery = location.search === '' && location.href.slice(0, location.href.length - window._cf_chl_opt.cOgUHash.length).indexOf('?') !== -1 ? '?' : location.search;if (window.history && window.history.replaceState) {var ogU = location.pathname + window._cf_chl_opt.cOgUQuery + window._cf_chl_opt.cOgUHash;history.replaceState(null, null,\"/backend-api/codex/analytics-events/events?__cf_chl_rt_tk=DJEasQvbq_8ptgz_GuTth3rmHBPpKfgSYmq.QhN_gxc-1774224283-1.0.1.1-ZrgUU9XtHSyU0timrL7wi6FhYUGpiMy.30xrbcy9gx0\"+ window._cf_chl_opt.cOgUHash);a.onload = function() {history.replaceState(null, null, ogU);}}document.getElementsByTagName('head')[0].appendChild(a);}());</script></div>\n    </div>\n  </body>\n</html>\n\n","stdout":"{\"type\":\"thread.started\",\"thread_id\":\"019d1801-9186-7922-b333-c05cc1bfb2f9\"}\n{\"type\":\"turn.started\"}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_0\",\"type\":\"agent_message\",\"text\":\"I’m continuing as CEO and will first load your required operating docs (`HEARTBEAT.md`, `SOUL.md`, `TOOLS.md`) from `$AGENT_HOME`, then execute the heartbeat checklist and proceed with the next Paperclip actions.\"}}\n{\"type\":\"item.started\",\"item\":{\"id\":\"item_1\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'ls -la agents/ceo'\",\"aggregated_output\":\"\",\"exit_code\":null,\"status\":\"in_progress\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_1\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'ls -la agents/ceo'\",\"aggregated_output\":\"total 32\\ndrwxr-xr-x@ 6 rock.xu  staff   192 Mar 23 08:02 .\\ndrwxr-xr-x@ 3 rock.xu  staff    96 Mar 23 08:02 ..\\n-rw-r--r--@ 1 rock.xu  staff  1221 Mar 23 08:02 AGENTS.md\\n-rw-r--r--@ 1 rock.xu  staff  2898 Mar 23 08:02 HEARTBEAT.md\\n-rw-r--r--@ 1 rock.xu  staff  2590 Mar 23 08:02 SOUL.md\\n-rw-r--r--@ 1 rock.xu  staff    86 Mar 23 08:02 TOOLS.md\\n\",\"exit_code\":0,\"status\":\"completed\"}}\n{\"type\":\"item.started\",\"item\":{\"id\":\"item_2\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'echo $AGENT_HOME && pwd && ls -la'\",\"aggregated_output\":\"\",\"exit_code\":null,\"status\":\"in_progress\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_2\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'echo $AGENT_HOME && pwd && ls -la'\",\"aggregated_output\":\"/Users/rock.xu/github/paperclip-demo/.paperclip-home/instances/demo/workspaces/d740f254-e1b7-4429-a639-dd1a34af65d1\\n/Users/rock.xu/github/paperclip-demo/.paperclip-home/instances/demo/workspaces/d740f254-e1b7-4429-a639-dd1a34af65d1\\ntotal 0\\ndrwxr-xr-x@ 3 rock.xu  staff  96 Mar 23 08:02 .\\ndrwxr-xr-x@ 3 rock.xu  staff  96 Mar 23 08:00 ..\\ndrwxr-xr-x@ 3 rock.xu  staff  96 Mar 23 08:02 agents\\n\",\"exit_code\":0,\"status\":\"completed\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_3\",\"type\":\"agent_message\",\"text\":\"I’ve confirmed `$AGENT_HOME` and the CEO folder. Next I’m reading the three required files and then I’ll execute the heartbeat protocol exactly.\"}}\n{\"type\":\"item.started\",\"item\":{\"id\":\"item_4\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'cat agents/ceo/HEARTBEAT.md'\",\"aggregated_output\":\"\",\"exit_code\":null,\"status\":\"in_progress\"}}\n{\"type\":\"item.started\",\"item\":{\"id\":\"item_5\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'cat agents/ceo/SOUL.md'\",\"aggregated_output\":\"\",\"exit_code\":null,\"status\":\"in_progress\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_4\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'cat agents/ceo/HEARTBEAT.md'\",\"aggregated_output\":\"# HEARTBEAT.md -- CEO Heartbeat Checklist\\n\\nRun this checklist on every heartbeat. This covers both your local planning/memory work and your organizational coordination via the Paperclip skill.\\n\\n## 1. Identity and Context\\n\\n- `GET /api/agents/me` -- confirm your id, role, budget, chainOfCommand.\\n- Check wake context: `PAPERCLIP_TASK_ID`, `PAPERCLIP_WAKE_REASON`, `PAPERCLIP_WAKE_COMMENT_ID`.\\n\\n## 2. Local Planning Check\\n\\n1. Read today's plan from `$AGENT_HOME/memory/YYYY-MM-DD.md` under \\\"## Today's Plan\\\".\\n2. Review each planned item: what's completed, what's blocked, and what up next.\\n3. For any blockers, resolve them yourself or escalate to the board.\\n4. If you're ahead, start on the next highest priority.\\n5. **Record progress updates** in the daily notes.\\n\\n## 3. Approval Follow-Up\\n\\nIf `PAPERCLIP_APPROVAL_ID` is set:\\n\\n- Review the approval and its linked issues.\\n- Close resolved issues or comment on what remains open.\\n\\n## 4. Get Assignments\\n\\n- `GET /api/companies/{companyId}/issues?assigneeAgentId={your-id}&status=todo,in_progress,blocked`\\n- Prioritize: `in_progress` first, then `todo`. Skip `blocked` unless you can unblock it.\\n- If there is already an active run on an `in_progress` task, just move on to the next thing.\\n- If `PAPERCLIP_TASK_ID` is set and assigned to you, prioritize that task.\\n\\n## 5. Checkout and Work\\n\\n- Always checkout before working: `POST /api/issues/{id}/checkout`.\\n- Never retry a 409 -- that task belongs to someone else.\\n- Do the work. Update status and comment when done.\\n\\n## 6. Delegation\\n\\n- Create subtasks with `POST /api/companies/{companyId}/issues`. Always set `parentId` and `goalId`.\\n- Use `paperclip-create-agent` skill when hiring new agents.\\n- Assign work to the right agent for the job.\\n\\n## 7. Fact Extraction\\n\\n1. Check for new conversations since last extraction.\\n2. Extract durable facts to the relevant entity in `$AGENT_HOME/life/` (PARA).\\n3. Update `$AGENT_HOME/memory/YYYY-MM-DD.md` with timeline entries.\\n4. Update access metadata (timestamp, access_count) for any referenced facts.\\n\\n## 8. Exit\\n\\n- Comment on any in_progress work before exiting.\\n- If no assignments and no valid mention-handoff, exit cleanly.\\n\\n---\\n\\n## CEO Responsibilities\\n\\n- **Strategic direction**: Set goals and priorities aligned with the company mission.\\n- **Hiring**: Spin up new agents when capacity is needed.\\n- **Unblocking**: Escalate or resolve blockers for reports.\\n- **Budget awareness**: Above 80% spend, focus only on critical tasks.\\n- **Never look for unassigned work** -- only work on what is assigned to you.\\n- **Never cancel cross-team tasks** -- reassign to the relevant manager with a comment.\\n\\n## Rules\\n\\n- Always use the Paperclip skill for coordination.\\n- Always include `X-Paperclip-Run-Id` header on mutating API calls.\\n- Comment in concise markdown: status line + bullets + links.\\n- Self-assign via checkout only when explicitly @-mentioned.\\n\",\"exit_code\":0,\"status\":\"completed\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_5\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'cat agents/ceo/SOUL.md'\",\"aggregated_output\":\"# SOUL.md -- CEO Persona\\n\\nYou are the CEO.\\n\\n## Strategic Posture\\n\\n- You own the P&L. Every decision rolls up to revenue, margin, and cash; if you miss the economics, no one else will catch them.\\n- Default to action. Ship over deliberate, because stalling usually costs more than a bad call.\\n- Hold the long view while executing the near term. Strategy without execution is a memo; execution without strategy is busywork.\\n- Protect focus hard. Say no to low-impact work; too many priorities are usually worse than a wrong one.\\n- In trade-offs, optimize for learning speed and reversibility. Move fast on two-way doors; slow down on one-way doors.\\n- Know the numbers cold. Stay within hours of truth on revenue, burn, runway, pipeline, conversion, and churn.\\n- Treat every dollar, headcount, and engineering hour as a bet. Know the thesis and expected return.\\n- Think in constraints, not wishes. Ask \\\"what do we stop?\\\" before \\\"what do we add?\\\"\\n- Hire slow, fire fast, and avoid leadership vacuums. The team is the strategy.\\n- Create organizational clarity. If priorities are unclear, it's on you; repeat strategy until it sticks.\\n- Pull for bad news and reward candor. If problems stop surfacing, you've lost your information edge.\\n- Stay close to the customer. Dashboards help, but regular firsthand conversations keep you honest.\\n- Be replaceable in operations and irreplaceable in judgment. Delegate execution; keep your time for strategy, capital allocation, key hires, and existential risk.\\n\\n## Voice and Tone\\n\\n- Be direct. Lead with the point, then give context. Never bury the ask.\\n- Write like you talk in a board meeting, not a blog post. Short sentences, active voice, no filler.\\n- Confident but not performative. You don't need to sound smart; you need to be clear.\\n- Match intensity to stakes. A product launch gets energy. A staffing call gets gravity. A Slack reply gets brevity.\\n- Skip the corporate warm-up. No \\\"I hope this message finds you well.\\\" Get to it.\\n- Use plain language. If a simpler word works, use it. \\\"Use\\\" not \\\"utilize.\\\" \\\"Start\\\" not \\\"initiate.\\\"\\n- Own uncertainty when it exists. \\\"I don't know yet\\\" beats a hedged non-answer every time.\\n- Disagree openly, but without heat. Challenge ideas, not people.\\n- Keep praise specific and rare enough to mean something. \\\"Good job\\\" is noise. \\\"The way you reframed the pricing model saved us a quarter\\\" is signal.\\n- Default to async-friendly writing. Structure with bullets, bold the key takeaway, assume the reader is skimming.\\n- No exclamation points unless something is genuinely on fire or genuinely worth celebrating.\\n\",\"exit_code\":0,\"status\":\"completed\"}}\n{\"type\":\"item.started\",\"item\":{\"id\":\"item_6\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'cat agents/ceo/TOOLS.md'\",\"aggregated_output\":\"\",\"exit_code\":null,\"status\":\"in_progress\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_6\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'cat agents/ceo/TOOLS.md'\",\"aggregated_output\":\"# Tools\\n\\n(Your tools will go here. Add notes about them as you acquire and use them.)\\n\",\"exit_code\":0,\"status\":\"completed\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_7\",\"type\":\"agent_message\",\"text\":\"I’m using two skills now: `paperclip` for all control-plane coordination and `para-memory-files` for daily plan/memory updates required by your heartbeat. I’ll load only the workflow sections needed to execute this cycle.\"}}\n{\"type\":\"item.started\",\"item\":{\"id\":\"item_8\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'cat /Users/rock.xu/github/paperclip-demo/runtime/node_modules/@paperclipai/adapter-codex-local/skills/paperclip/SKILL.md'\",\"aggregated_output\":\"\",\"exit_code\":null,\"status\":\"in_progress\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_8\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'cat /Users/rock.xu/github/paperclip-demo/runtime/node_modules/@paperclipai/adapter-codex-local/skills/paperclip/SKILL.md'\",\"aggregated_output\":\"---\\nname: paperclip\\ndescription: >\\n  Interact with the Paperclip control plane API to manage tasks, coordinate with\\n  other agents, and follow company governance. Use when you need to check\\n  assignments, update task status, delegate work, post comments, or call any\\n  Paperclip API endpoint. Do NOT use for the actual domain work itself (writing\\n  code, research, etc.) — only for Paperclip coordination.\\n---\\n\\n# Paperclip Skill\\n\\nYou run in **heartbeats** — short execution windows triggered by Paperclip. Each heartbeat, you wake up, check your work, do something useful, and exit. You do not run continuously.\\n\\n## Authentication\\n\\nEnv vars auto-injected: `PAPERCLIP_AGENT_ID`, `PAPERCLIP_COMPANY_ID`, `PAPERCLIP_API_URL`, `PAPERCLIP_RUN_ID`. Optional wake-context vars may also be present: `PAPERCLIP_TASK_ID` (issue/task that triggered this wake), `PAPERCLIP_WAKE_REASON` (why this run was triggered), `PAPERCLIP_WAKE_COMMENT_ID` (specific comment that triggered this wake), `PAPERCLIP_APPROVAL_ID`, `PAPERCLIP_APPROVAL_STATUS`, and `PAPERCLIP_LINKED_ISSUE_IDS` (comma-separated). For local adapters, `PAPERCLIP_API_KEY` is auto-injected as a short-lived run JWT. For non-local adapters, your operator should set `PAPERCLIP_API_KEY` in adapter config. All requests use `Authorization: Bearer $PAPERCLIP_API_KEY`. All endpoints under `/api`, all JSON. Never hard-code the API URL.\\n\\nManual local CLI mode (outside heartbeat runs): use `paperclipai agent local-cli <agent-id-or-shortname> --company-id <company-id>` to install Paperclip skills for Claude/Codex and print/export the required `PAPERCLIP_*` environment variables for that agent identity.\\n\\n**Run audit trail:** You MUST include `-H 'X-Paperclip-Run-Id: $PAPERCLIP_RUN_ID'` on ALL API requests that modify issues (checkout, update, comment, create subtask, release). This links your actions to the current heartbeat run for traceability.\\n\\n## The Heartbeat Procedure\\n\\nFollow these steps every time you wake up:\\n\\n**Step 1 — Identity.** If not already in context, `GET /api/agents/me` to get your id, companyId, role, chainOfCommand, and budget.\\n\\n**Step 2 — Approval follow-up (when triggered).** If `PAPERCLIP_APPROVAL_ID` is set (or wake reason indicates approval resolution), review the approval first:\\n\\n- `GET /api/approvals/{approvalId}`\\n- `GET /api/approvals/{approvalId}/issues`\\n- For each linked issue:\\n  - close it (`PATCH` status to `done`) if the approval fully resolves requested work, or\\n  - add a markdown comment explaining why it remains open and what happens next.\\n    Always include links to the approval and issue in that comment.\\n\\n**Step 3 — Get assignments.** Prefer `GET /api/agents/me/inbox-lite` for the normal heartbeat inbox. It returns the compact assignment list you need for prioritization. Fall back to `GET /api/companies/{companyId}/issues?assigneeAgentId={your-agent-id}&status=todo,in_progress,blocked` only when you need the full issue objects.\\n\\n**Step 4 — Pick work (with mention exception).** Work on `in_progress` first, then `todo`. Skip `blocked` unless you can unblock it.\\n**Blocked-task dedup:** Before working on a `blocked` task, fetch its comment thread. If your most recent comment was a blocked-status update AND no new comments from other agents or users have been posted since, skip the task entirely — do not checkout, do not post another comment. Exit the heartbeat (or move to the next task) instead. Only re-engage with a blocked task when new context exists (a new comment, status change, or event-based wake like `PAPERCLIP_WAKE_COMMENT_ID`).\\nIf `PAPERCLIP_TASK_ID` is set and that task is assigned to you, prioritize it first for this heartbeat.\\nIf this run was triggered by a comment mention (`PAPERCLIP_WAKE_COMMENT_ID` set; typically `PAPERCLIP_WAKE_REASON=issue_comment_mentioned`), you MUST read that comment thread first, even if the task is not currently assigned to you.\\nIf that mentioned comment explicitly asks you to take the task, you may self-assign by checking out `PAPERCLIP_TASK_ID` as yourself, then proceed normally.\\nIf the comment asks for input/review but not ownership, respond in comments if useful, then continue with assigned work.\\nIf the comment does not direct you to take ownership, do not self-assign.\\nIf nothing is assigned and there is no valid mention-based ownership handoff, exit the heartbeat.\\n\\n**Step 5 — Checkout.** You MUST checkout before doing any work. Include the run ID header:\\n\\n```\\nPOST /api/issues/{issueId}/checkout\\nHeaders: Authorization: Bearer $PAPERCLIP_API_KEY, X-Paperclip-Run-Id: $PAPERCLIP_RUN_ID\\n{ \\\"agentId\\\": \\\"{your-agent-id}\\\", \\\"expectedStatuses\\\": [\\\"todo\\\", \\\"backlog\\\", \\\"blocked\\\"] }\\n```\\n\\nIf already checked out by you, returns normally. If owned by another agent: `409 Conflict` — stop, pick a different task. **Never retry a 409.**\\n\\n**Step 6 — Understand context.** Prefer `GET /api/issues/{issueId}/heartbeat-context` first. It gives you compact issue state, ancestor summaries, goal/project info, and comment cursor metadata without forcing a full thread replay.\\n\\nUse comments incrementally:\\n\\n- if `PAPERCLIP_WAKE_COMMENT_ID` is set, fetch that exact comment first with `GET /api/issues/{issueId}/comments/{commentId}`\\n- if you already know the thread and only need updates, use `GET /api/issues/{issueId}/comments?after={last-seen-comment-id}&order=asc`\\n- use the full `GET /api/issues/{issueId}/comments` route only when you are cold-starting, when session memory is unreliable, or when the incremental path is not enough\\n\\nRead enough ancestor/comment context to understand _why_ the task exists and what changed. Do not reflexively reload the whole thread on every heartbeat.\\n\\n**Step 7 — Do the work.** Use your tools and capabilities.\\n\\n**Step 8 — Update status and communicate.** Always include the run ID header.\\nIf you are blocked at any point, you MUST update the issue to `blocked` before exiting the heartbeat, with a comment that explains the blocker and who needs to act.\\n\\n```json\\nPATCH /api/issues/{issueId}\\nHeaders: X-Paperclip-Run-Id: $PAPERCLIP_RUN_ID\\n{ \\\"status\\\": \\\"done\\\", \\\"comment\\\": \\\"What was done and why.\\\" }\\n\\nPATCH /api/issues/{issueId}\\nHeaders: X-Paperclip-Run-Id: $PAPERCLIP_RUN_ID\\n{ \\\"status\\\": \\\"blocked\\\", \\\"comment\\\": \\\"What is blocked, why, and who needs to unblock it.\\\" }\\n```\\n\\nStatus values: `backlog`, `todo`, `in_progress`, `in_review`, `done`, `blocked`, `cancelled`. Priority values: `critical`, `high`, `medium`, `low`. Other updatable fields: `title`, `description`, `priority`, `assigneeAgentId`, `projectId`, `goalId`, `parentId`, `billingCode`.\\n\\n**Step 9 — Delegate if needed.** Create subtasks with `POST /api/companies/{companyId}/issues`. Always set `parentId` and `goalId`. Set `billingCode` for cross-team work.\\n\\n## Project Setup Workflow (CEO/Manager Common Path)\\n\\nWhen asked to set up a new project with workspace config (local folder and/or GitHub repo), use:\\n\\n1. `POST /api/companies/{companyId}/projects` with project fields.\\n2. Optionally include `workspace` in that same create call, or call `POST /api/projects/{projectId}/workspaces` right after create.\\n\\nWorkspace rules:\\n\\n- Provide at least one of `cwd` (local folder) or `repoUrl` (remote repo).\\n- For repo-only setup, omit `cwd` and provide `repoUrl`.\\n- Include both `cwd` + `repoUrl` when local and remote references should both be tracked.\\n\\n## OpenClaw Invite Workflow (CEO)\\n\\nUse this when asked to invite a new OpenClaw employee.\\n\\n1. Generate a fresh OpenClaw invite prompt:\\n\\n```\\nPOST /api/companies/{companyId}/openclaw/invite-prompt\\n{ \\\"agentMessage\\\": \\\"optional onboarding note for OpenClaw\\\" }\\n```\\n\\nAccess control:\\n\\n- Board users with invite permission can call it.\\n- Agent callers: only the company CEO agent can call it.\\n\\n2. Build the copy-ready OpenClaw prompt for the board:\\n\\n- Use `onboardingTextUrl` from the response.\\n- Ask the board to paste that prompt into OpenClaw.\\n- If the issue includes an OpenClaw URL (for example `ws://127.0.0.1:18789`), include that URL in your comment so the board/OpenClaw uses it in `agentDefaultsPayload.url`.\\n\\n3. Post the prompt in the issue comment so the human can paste it into OpenClaw.\\n\\n4. After OpenClaw submits the join request, monitor approvals and continue onboarding (approval + API key claim + skill install).\\n\\n## Critical Rules\\n\\n- **Always checkout** before working. Never PATCH to `in_progress` manually.\\n- **Never retry a 409.** The task belongs to someone else.\\n- **Never look for unassigned work.**\\n- **Self-assign only for explicit @-mention handoff.** This requires a mention-triggered wake with `PAPERCLIP_WAKE_COMMENT_ID` and a comment that clearly directs you to do the task. Use checkout (never direct assignee patch). Otherwise, no assignments = exit.\\n- **Honor \\\"send it back to me\\\" requests from board users.** If a board/user asks for review handoff (e.g. \\\"let me review it\\\", \\\"assign it back to me\\\"), reassign the issue to that user with `assigneeAgentId: null` and `assigneeUserId: \\\"<requesting-user-id>\\\"`, and typically set status to `in_review` instead of `done`.\\n  Resolve requesting user id from the triggering comment thread (`authorUserId`) when available; otherwise use the issue's `createdByUserId` if it matches the requester context.\\n- **Always comment** on `in_progress` work before exiting a heartbeat — **except** for blocked tasks with no new context (see blocked-task dedup in Step 4).\\n- **Always set `parentId`** on subtasks (and `goalId` unless you're CEO/manager creating top-level work).\\n- **Never cancel cross-team tasks.** Reassign to your manager with a comment.\\n- **Always update blocked issues explicitly.** If blocked, PATCH status to `blocked` with a blocker comment before exiting, then escalate. On subsequent heartbeats, do NOT repeat the same blocked comment — see blocked-task dedup in Step 4.\\n- **@-mentions** (`@AgentName` in comments) trigger heartbeats — use sparingly, they cost budget.\\n- **Budget**: auto-paused at 100%. Above 80%, focus on critical tasks only.\\n- **Escalate** via `chainOfCommand` when stuck. Reassign to manager or create a task for them.\\n- **Hiring**: use `paperclip-create-agent` skill for new agent creation workflows.\\n- **Commit Co-author**: if you make a git commit you MUST add `Co-Authored-By: Paperclip <noreply@paperclip.ing>` to the end of each commit message\\n\\n## Comment Style (Required)\\n\\nWhen posting issue comments, use concise markdown with:\\n\\n- a short status line\\n- bullets for what changed / what is blocked\\n- links to related entities when available\\n\\n**Company-prefixed URLs (required):** All internal links MUST include the company prefix. Derive the prefix from any issue identifier you have (e.g., `PAP-315` → prefix is `PAP`). Use this prefix in all UI links:\\n\\n- Issues: `/<prefix>/issues/<issue-identifier>` (e.g., `/PAP/issues/PAP-224`)\\n- Issue comments: `/<prefix>/issues/<issue-identifier>#comment-<comment-id>` (deep link to a specific comment)\\n- Issue documents: `/<prefix>/issues/<issue-identifier>#document-<document-key>` (deep link to a specific document such as `plan`)\\n- Agents: `/<prefix>/agents/<agent-url-key>` (e.g., `/PAP/agents/claudecoder`)\\n- Projects: `/<prefix>/projects/<project-url-key>` (id fallback allowed)\\n- Approvals: `/<prefix>/approvals/<approval-id>`\\n- Runs: `/<prefix>/agents/<agent-url-key-or-id>/runs/<run-id>`\\n\\nDo NOT use unprefixed paths like `/issues/PAP-123` or `/agents/cto` — always include the company prefix.\\n\\nExample:\\n\\n```md\\n## Update\\n\\nSubmitted CTO hire request and linked it for board review.\\n\\n- Approval: [ca6ba09d](/PAP/approvals/ca6ba09d-b558-4a53-a552-e7ef87e54a1b)\\n- Pending agent: [CTO draft](/PAP/agents/cto)\\n- Source issue: [PC-142](/PAP/issues/PC-142)\\n```\\n\\n## Planning (Required when planning requested)\\n\\nIf you're asked to make a plan, create or update the issue document with key `plan`. Do not append plans into the issue description anymore. If you're asked for plan revisions, update that same `plan` document. In both cases, leave a comment as you normally would and mention that you updated the plan document.\\n\\nWhen you mention a plan or another issue document in a comment, include a direct document link using the key:\\n\\n- Plan: `/<prefix>/issues/<issue-identifier>#document-plan`\\n- Generic document: `/<prefix>/issues/<issue-identifier>#document-<document-key>`\\n\\nIf the issue identifier is available, prefer the document deep link over a plain issue link so the reader lands directly on the updated document.\\n\\nIf you're asked to make a plan, _do not mark the issue as done_. Re-assign the issue to whomever asked you to make the plan and leave it in progress.\\n\\nRecommended API flow:\\n\\n```bash\\nPUT /api/issues/{issueId}/documents/plan\\n{\\n  \\\"title\\\": \\\"Plan\\\",\\n  \\\"format\\\": \\\"markdown\\\",\\n  \\\"body\\\": \\\"# Plan\\\\n\\\\n[your plan here]\\\",\\n  \\\"baseRevisionId\\\": null\\n}\\n```\\n\\nIf `plan` already exists, fetch the current document first and send its latest `baseRevisionId` when you update it.\\n\\n## Setting Agent Instructions Path\\n\\nUse the dedicated route instead of generic `PATCH /api/agents/:id` when you need to set an agent's instructions markdown path (for example `AGENTS.md`).\\n\\n```bash\\nPATCH /api/agents/{agentId}/instructions-path\\n{\\n  \\\"path\\\": \\\"agents/cmo/AGENTS.md\\\"\\n}\\n```\\n\\nRules:\\n\\n- Allowed for: the target agent itself, or an ancestor manager in that agent's reporting chain.\\n- For `codex_local` and `claude_local`, default config key is `instructionsFilePath`.\\n- Relative paths are resolved against the target agent's `adapterConfig.cwd`; absolute paths are accepted as-is.\\n- To clear the path, send `{ \\\"path\\\": null }`.\\n- For adapters with a different key, provide it explicitly:\\n\\n```bash\\nPATCH /api/agents/{agentId}/instructions-path\\n{\\n  \\\"path\\\": \\\"/absolute/path/to/AGENTS.md\\\",\\n  \\\"adapterConfigKey\\\": \\\"yourAdapterSpecificPathField\\\"\\n}\\n```\\n\\n## Key Endpoints (Quick Reference)\\n\\n| Action                                | Endpoint                                                                                   |\\n| ------------------------------------- | ------------------------------------------------------------------------------------------ |\\n| My identity                           | `GET /api/agents/me`                                                                       |\\n| My compact inbox                      | `GET /api/agents/me/inbox-lite`                                                            |\\n| My assignments                        | `GET /api/companies/:companyId/issues?assigneeAgentId=:id&status=todo,in_progress,blocked` |\\n| Checkout task                         | `POST /api/issues/:issueId/checkout`                                                       |\\n| Get task + ancestors                  | `GET /api/issues/:issueId`                                                                 |\\n| List issue documents                  | `GET /api/issues/:issueId/documents`                                                       |\\n| Get issue document                    | `GET /api/issues/:issueId/documents/:key`                                                  |\\n| Create/update issue document          | `PUT /api/issues/:issueId/documents/:key`                                                  |\\n| Get issue document revisions          | `GET /api/issues/:issueId/documents/:key/revisions`                                        |\\n| Get compact heartbeat context         | `GET /api/issues/:issueId/heartbeat-context`                                               |\\n| Get comments                          | `GET /api/issues/:issueId/comments`                                                        |\\n| Get comment delta                     | `GET /api/issues/:issueId/comments?after=:commentId&order=asc`                             |\\n| Get specific comment                  | `GET /api/issues/:issueId/comments/:commentId`                                             |\\n| Update task                           | `PATCH /api/issues/:issueId` (optional `comment` field)                                    |\\n| Add comment                           | `POST /api/issues/:issueId/comments`                                                       |\\n| Create subtask                        | `POST /api/companies/:companyId/issues`                                                    |\\n| Generate OpenClaw invite prompt (CEO) | `POST /api/companies/:companyId/openclaw/invite-prompt`                                    |\\n| Create project                        | `POST /api/companies/:companyId/projects`                                                  |\\n| Create project workspace              | `POST /api/projects/:projectId/workspaces`                                                 |\\n| Set instructions path                 | `PATCH /api/agents/:agentId/instructions-path`                                             |\\n| Release task                          | `POST /api/issues/:issueId/release`                                                        |\\n| List agents                           | `GET /api/companies/:companyId/agents`                                                     |\\n| Dashboard                             | `GET /api/companies/:companyId/dashboard`                                                  |\\n| Search issues                         | `GET /api/companies/:companyId/issues?q=search+term`                                       |\\n\\n## Searching Issues\\n\\nUse the `q` query parameter on the issues list endpoint to search across titles, identifiers, descriptions, and comments:\\n\\n```\\nGET /api/companies/{companyId}/issues?q=dockerfile\\n```\\n\\nResults are ranked by relevance: title matches first, then identifier, description, and comments. You can combine `q` with other filters (`status`, `assigneeAgentId`, `projectId`, `labelId`).\\n\\n## Self-Test Playbook (App-Level)\\n\\nUse this when validating Paperclip itself (assignment flow, checkouts, run visibility, and status transitions).\\n\\n1. Create a throwaway issue assigned to a known local agent (`claudecoder` or `codexcoder`):\\n\\n```bash\\npnpm paperclipai issue create \\\\\\n  --company-id \\\"$PAPERCLIP_COMPANY_ID\\\" \\\\\\n  --title \\\"Self-test: assignment/watch flow\\\" \\\\\\n  --description \\\"Temporary validation issue\\\" \\\\\\n  --status todo \\\\\\n  --assignee-agent-id \\\"$PAPERCLIP_AGENT_ID\\\"\\n```\\n\\n2. Trigger and watch a heartbeat for that assignee:\\n\\n```bash\\npnpm paperclipai heartbeat run --agent-id \\\"$PAPERCLIP_AGENT_ID\\\"\\n```\\n\\n3. Verify the issue transitions (`todo -> in_progress -> done` or `blocked`) and that comments are posted:\\n\\n```bash\\npnpm paperclipai issue get <issue-id-or-identifier>\\n```\\n\\n4. Reassignment test (optional): move the same issue between `claudecoder` and `codexcoder` and confirm wake/run behavior:\\n\\n```bash\\npnpm paperclipai issue update <issue-id> --assignee-agent-id <other-agent-id> --status todo\\n```\\n\\n5. Cleanup: mark temporary issues done/cancelled with a clear note.\\n\\nIf you use direct `curl` during these tests, include `X-Paperclip-Run-Id` on all mutating issue requests whenever running inside a heartbeat.\\n\\n## Full Reference\\n\\nFor detailed API tables, JSON response schemas, worked examples (IC and Manager heartbeats), governance/approvals, cross-team delegation rules, error codes, issue lifecycle diagram, and the common mistakes table, read: `skills/paperclip/references/api-reference.md`\\n\",\"exit_code\":0,\"status\":\"completed\"}}\n{\"type\":\"item.started\",\"item\":{\"id\":\"item_9\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'cat /Users/rock.xu/github/paperclip-demo/runtime/node_modules/@paperclipai/adapter-codex-local/skills/para-memory-files/SKILL.md'\",\"aggregated_output\":\"\",\"exit_code\":null,\"status\":\"in_progress\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_9\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'cat /Users/rock.xu/github/paperclip-demo/runtime/node_modules/@paperclipai/adapter-codex-local/skills/para-memory-files/SKILL.md'\",\"aggregated_output\":\"---\\nname: para-memory-files\\ndescription: >\\n  File-based memory system using Tiago Forte's PARA method. Use this skill whenever\\n  you need to store, retrieve, update, or organize knowledge across sessions. Covers\\n  three memory layers: (1) Knowledge graph in PARA folders with atomic YAML facts,\\n  (2) Daily notes as raw timeline, (3) Tacit knowledge about user patterns. Also\\n  handles planning files, memory decay, weekly synthesis, and recall via qmd.\\n  Trigger on any memory operation: saving facts, writing daily notes, creating\\n  entities, running weekly synthesis, recalling past context, or managing plans.\\n---\\n\\n# PARA Memory Files\\n\\nPersistent, file-based memory organized by Tiago Forte's PARA method. Three layers: a knowledge graph, daily notes, and tacit knowledge. All paths are relative to `$AGENT_HOME`.\\n\\n## Three Memory Layers\\n\\n### Layer 1: Knowledge Graph (`$AGENT_HOME/life/` -- PARA)\\n\\nEntity-based storage. Each entity gets a folder with two tiers:\\n\\n1. `summary.md` -- quick context, load first.\\n2. `items.yaml` -- atomic facts, load on demand.\\n\\n```text\\n$AGENT_HOME/life/\\n  projects/          # Active work with clear goals/deadlines\\n    <name>/\\n      summary.md\\n      items.yaml\\n  areas/             # Ongoing responsibilities, no end date\\n    people/<name>/\\n    companies/<name>/\\n  resources/         # Reference material, topics of interest\\n    <topic>/\\n  archives/          # Inactive items from the other three\\n  index.md\\n```\\n\\n**PARA rules:**\\n\\n- **Projects** -- active work with a goal or deadline. Move to archives when complete.\\n- **Areas** -- ongoing (people, companies, responsibilities). No end date.\\n- **Resources** -- reference material, topics of interest.\\n- **Archives** -- inactive items from any category.\\n\\n**Fact rules:**\\n\\n- Save durable facts immediately to `items.yaml`.\\n- Weekly: rewrite `summary.md` from active facts.\\n- Never delete facts. Supersede instead (`status: superseded`, add `superseded_by`).\\n- When an entity goes inactive, move its folder to `$AGENT_HOME/life/archives/`.\\n\\n**When to create an entity:**\\n\\n- Mentioned 3+ times, OR\\n- Direct relationship to the user (family, coworker, partner, client), OR\\n- Significant project or company in the user's life.\\n- Otherwise, note it in daily notes.\\n\\nFor the atomic fact YAML schema and memory decay rules, see [references/schemas.md](references/schemas.md).\\n\\n### Layer 2: Daily Notes (`$AGENT_HOME/memory/YYYY-MM-DD.md`)\\n\\nRaw timeline of events -- the \\\"when\\\" layer.\\n\\n- Write continuously during conversations.\\n- Extract durable facts to Layer 1 during heartbeats.\\n\\n### Layer 3: Tacit Knowledge (`$AGENT_HOME/MEMORY.md`)\\n\\nHow the user operates -- patterns, preferences, lessons learned.\\n\\n- Not facts about the world; facts about the user.\\n- Update whenever you learn new operating patterns.\\n\\n## Write It Down -- No Mental Notes\\n\\nMemory does not survive session restarts. Files do.\\n\\n- Want to remember something -> WRITE IT TO A FILE.\\n- \\\"Remember this\\\" -> update `$AGENT_HOME/memory/YYYY-MM-DD.md` or the relevant entity file.\\n- Learn a lesson -> update AGENTS.md, TOOLS.md, or the relevant skill file.\\n- Make a mistake -> document it so future-you does not repeat it.\\n- On-disk text files are always better than holding it in temporary context.\\n\\n## Memory Recall -- Use qmd\\n\\nUse `qmd` rather than grepping files:\\n\\n```bash\\nqmd query \\\"what happened at Christmas\\\"   # Semantic search with reranking\\nqmd search \\\"specific phrase\\\"              # BM25 keyword search\\nqmd vsearch \\\"conceptual question\\\"         # Pure vector similarity\\n```\\n\\nIndex your personal folder: `qmd index $AGENT_HOME`\\n\\nVectors + BM25 + reranking finds things even when the wording differs.\\n\\n## Planning\\n\\nKeep plans in timestamped files in `plans/` at the project root (outside personal memory so other agents can access them). Use `qmd` to search plans. Plans go stale -- if a newer plan exists, do not confuse yourself with an older version. If you notice staleness, update the file to note what it is supersededBy.\\n\",\"exit_code\":0,\"status\":\"completed\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_10\",\"type\":\"agent_message\",\"text\":\"I’ve loaded both skill workflows. Next I’m running the heartbeat sequence: identity, wake-context/env check, inbox retrieval, then I’ll sync today’s memory note and record progress there.\"}}\n{\"type\":\"item.started\",\"item\":{\"id\":\"item_11\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc \\\"printenv | rg '\\\"'^PAPERCLIP_|''^AGENT_HOME|''^HOME'\\\"' | sort\\\"\",\"aggregated_output\":\"\",\"exit_code\":null,\"status\":\"in_progress\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_11\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc \\\"printenv | rg '\\\"'^PAPERCLIP_|''^AGENT_HOME|''^HOME'\\\"' | sort\\\"\",\"aggregated_output\":\"AGENT_HOME=/Users/rock.xu/github/paperclip-demo/.paperclip-home/instances/demo/workspaces/d740f254-e1b7-4429-a639-dd1a34af65d1\\nHOME=/Users/rock.xu\\nHOMEBREW_CELLAR=/opt/homebrew/Cellar\\nHOMEBREW_PREFIX=/opt/homebrew\\nHOMEBREW_REPOSITORY=/opt/homebrew\\nPAPERCLIP_AGENT_ID=d740f254-e1b7-4429-a639-dd1a34af65d1\\nPAPERCLIP_AGENT_JWT_SECRET=1c6ad87bba0767c5fdb40d0909c00d3e5eb71fdf534235655b25189dac175edc\\nPAPERCLIP_API_KEY=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9..C6pTEReGXEOcSuSmqnni5S3xaXgRGZzLGF490JdS1wY\\nPAPERCLIP_API_URL=http://127.0.0.1:3100\\nPAPERCLIP_COMPANY_ID=8e6a9f7a-8cc9-4d7f-80f1-ddd498291f7e\\nPAPERCLIP_CONFIG=/Users/rock.xu/github/paperclip-demo/.paperclip-home/config.json\\nPAPERCLIP_HOME=/Users/rock.xu/github/paperclip-demo/.paperclip-home\\nPAPERCLIP_INSTANCE_ID=demo\\nPAPERCLIP_LISTEN_HOST=127.0.0.1\\nPAPERCLIP_LISTEN_PORT=3100\\nPAPERCLIP_OPEN_ON_LISTEN=false\\nPAPERCLIP_RUN_ID=9ccf8add-f177-4303-931d-94a258fc4e5e\\nPAPERCLIP_SECRETS_MASTER_KEY_FILE=/Us