eted\",\"item\":{\"id\":\"item_18\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'curl -sS -H \\\"Authorization: Bearer $PAPERCLIP_API_KEY\\\" \\\"$PAPERCLIP_API_URL/api/issues/$PAPERCLIP_TASK_ID/heartbeat-context\\\"'\",\"aggregated_output\":\"{\\\"issue\\\":{\\\"id\\\":\\\"9de984e4-f449-42c4-af0f-13d526afc077\\\",\\\"identifier\\\":\\\"ABC-2\\\",\\\"title\\\":\\\"Approve and onboard Founding Engineer\\\",\\\"description\\\":\\\"Track board approval for the pending Founding Engineer hire, then complete onboarding and first assignment handoff.\\\",\\\"status\\\":\\\"todo\\\",\\\"priority\\\":\\\"high\\\",\\\"projectId\\\":null,\\\"goalId\\\":null,\\\"parentId\\\":null,\\\"assigneeAgentId\\\":\\\"d740f254-e1b7-4429-a639-dd1a34af65d1\\\",\\\"assigneeUserId\\\":null,\\\"updatedAt\\\":\\\"2026-03-23T00:03:28.480Z\\\"},\\\"ancestors\\\":[],\\\"project\\\":null,\\\"goal\\\":null,\\\"commentCursor\\\":{\\\"totalComments\\\":0,\\\"latestCommentId\\\":null,\\\"latestCommentAt\\\":null},\\\"wakeComment\\\":null}\",\"exit_code\":0,\"status\":\"completed\"}}\n{\"type\":\"item.started\",\"item\":{\"id\":\"item_19\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'curl -sS -X POST \\\"$PAPERCLIP_API_URL/api/issues/$PAPERCLIP_TASK_ID/checkout\\\" -H \\\"Authorization: Bearer $PAPERCLIP_API_KEY\\\" -H \\\"Content-Type: application/json\\\" -H \\\"X-Paperclip-Run-Id: $PAPERCLIP_RUN_ID\\\" --data '\\\"'{\\\\\\\"agentId\\\\\\\":\\\\\\\"'\\\"'$PAPERCLIP_AGENT_ID'\\\"'\\\\\\\",\\\\\\\"expectedStatuses\\\\\\\":[\\\\\\\"todo\\\\\\\",\\\\\\\"backlog\\\\\\\",\\\\\\\"blocked\\\\\\\"]}'\\\"\",\"aggregated_output\":\"\",\"exit_code\":null,\"status\":\"in_progress\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_19\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'curl -sS -X POST \\\"$PAPERCLIP_API_URL/api/issues/$PAPERCLIP_TASK_ID/checkout\\\" -H \\\"Authorization: Bearer $PAPERCLIP_API_KEY\\\" -H \\\"Content-Type: application/json\\\" -H \\\"X-Paper