tId\\\":null,\\\"updatedAt\\\":\\\"2026-03-23T00:03:28.576Z\\\",\\\"activeRun\\\":{\\\"id\\\":\\\"5e9051c4-8466-40fc-a5ec-7c35550e8bb0\\\",\\\"status\\\":\\\"running\\\",\\\"agentId\\\":\\\"d740f254-e1b7-4429-a639-dd1a34af65d1\\\",\\\"invocationSource\\\":\\\"assignment\\\",\\\"triggerDetail\\\":\\\"system\\\",\\\"startedAt\\\":\\\"2026-03-23T00:08:16.011Z\\\",\\\"finishedAt\\\":null,\\\"createdAt\\\":\\\"2026-03-23T00:03:28.563Z\\\"}}]\",\"exit_code\":0,\"status\":\"completed\"}}\n{\"type\":\"item.completed\",\"item\":{\"id\":\"item_13\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'curl -sS \\\"$PAPERCLIP_API_URL/api/agents/me\\\" -H \\\"Authorization: Bearer $PAPERCLIP_API_KEY\\\"'\",\"aggregated_output\":\"{\\\"id\\\":\\\"d740f254-e1b7-4429-a639-dd1a34af65d1\\\",\\\"companyId\\\":\\\"8e6a9f7a-8cc9-4d7f-80f1-ddd498291f7e\\\",\\\"name\\\":\\\"CEO\\\",\\\"role\\\":\\\"ceo\\\",\\\"title\\\":null,\\\"icon\\\":null,\\\"status\\\":\\\"running\\\",\\\"reportsTo\\\":null,\\\"capabilities\\\":null,\\\"adapterType\\\":\\\"codex_local\\\",\\\"adapterConfig\\\":{\\\"model\\\":\\\"gpt-5.3-codex\\\",\\\"search\\\":false,\\\"graceSec\\\":15,\\\"timeoutSec\\\":0,\\\"instructionsFilePath\\\":\\\"/Users/rock.xu/github/paperclip-demo/.paperclip-home/instances/demo/workspaces/d740f254-e1b7-4429-a639-dd1a34af65d1/agents/ceo/AGENTS.md\\\",\\\"dangerouslyBypassApprovalsAndSandbox\\\":true},\\\"runtimeConfig\\\":{\\\"heartbeat\\\":{\\\"enabled\\\":true,\\\"cooldownSec\\\":10,\\\"intervalSec\\\":3600,\\\"wakeOnDemand\\\":true,\\\"maxConcurrentRuns\\\":1}},\\\"budgetMonthlyCents\\\":0,\\\"spentMonthlyCents\\\":0,\\\"pauseReason\\\":null,\\\"pausedAt\\\":null,\\\"permissions\\\":{\\\"canCreateAgents\\\":true},\\\"lastHeartbeatAt\\\":\\\"2026-03-23T00:08:16.000Z\\\",\\\"metadata\\\":null,\\\"createdAt\\\":\\\"2026-03-23T00:00:47.530Z\\\",\\\"updatedAt\\\":\\\"2026-03-23T00:08:16.025Z\\\",\\\"urlKey\\\":\\\"ceo\\\",\\\"chainOfCommand\\\":[]}\",\"exit_code\":0,\"status\":\"comple